import { notFound } from 'next/navigation'
import type { Metadata } from 'next'
import { getNicheById, getAllNicheIds } from '@/lib/niches'
import { Navigation } from '@/components/navigation'
import { NicheHero } from '@/components/niche-hero'
import { PainPointsSection } from '@/components/pain-points-section'

interface NichePageProps {
  params: {
    niche: string
  }
}

export async function generateStaticParams() {
  const nicheIds = getAllNicheIds()
  return nicheIds.map((id) => ({
    niche: id,
  }))
}

export async function generateMetadata({ params }: NichePageProps): Promise<Metadata> {
  const resolvedParams = await params
  const niche = getNicheById(resolvedParams.niche)

  if (!niche) {
    return {
      title: 'Page Not Found - FlowNexis3',
    }
  }

  return {
    title: `${niche.name} | ${niche.tagline} - FlowNexis3`,
    description: niche.description,
    keywords: `${niche.industry}, AI automation, ${niche.targetAudience.join(', ')}, FlowNexis3`,
    openGraph: {
      title: `${niche.name} | ${niche.tagline}`,
      description: niche.description,
      type: 'website',
    },
    twitter: {
      card: 'summary_large_image',
      title: `${niche.name} | ${niche.tagline}`,
      description: niche.description,
    },
  }
}

export default async function NichePage({ params }: NichePageProps) {
  const resolvedParams = await params
  const niche = getNicheById(resolvedParams.niche)

  if (!niche) {
    notFound()
  }

  return (
    <main className="relative">
      <Navigation />
      <NicheHero niche={niche} />
      <PainPointsSection niche={niche} />
    </main>
  )
}